from flask import Flask, request, jsonify
from prometheus_client import Counter, Histogram, generate_latest
import prometheus_client

app = Flask(__name__)

REQUEST_COUNT = Counter('request_count', 'Total Request Count', ['method', 'endpoint', 'user_id', 'api_key'])
REQUEST_LATENCY = Histogram('request_latency_seconds', 'Request latency', ['method', 'endpoint', 'user_id', 'api_key'])

@app.before_request
def start_timer():
    request.start_time = prometheus_client.utils.time()

@app.after_request
def record_metrics(response):
    request_latency = prometheus_client.utils.time() - request.start_time
    user_id = request.headers.get('User-ID', 'unknown')
    api_key = request.headers.get('API-Key', 'unknown')
    REQUEST_COUNT.labels(request.method, request.path, user_id, api_key).inc()
    REQUEST_LATENCY.labels(request.method, request.path, user_id, api_key).observe(request_latency)
    return response

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': 'text/plain; charset=utf-8'}

@app.route('/api', methods=['POST'])
def api():
    data = request.json
    return jsonify({"status": "success", "data": data}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)